frappe.pages["construcontrol-dashboard"].on_page_load = function (wrapper) {
    const page = frappe.ui.make_app_page({ parent: wrapper, title: "ConstruControl", single_column: true });
    const body = $(wrapper).find(".layout-main-section");
    body.html(`
      <style>
        .cc-hero{padding:22px;border:1px solid var(--border-color);border-radius:14px;background:var(--card-bg);margin-bottom:16px}.cc-hero h2{margin:0 0 6px}.cc-muted{color:var(--text-muted)}
        .cc-metrics{display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:12px;margin:16px 0}.cc-metric{border:1px solid var(--border-color);border-radius:12px;padding:14px;background:var(--card-bg)}.cc-metric strong{display:block;font-size:22px;margin-top:5px}
        .cc-modules{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px}.cc-module{display:block;border:1px solid var(--border-color);border-radius:12px;padding:14px;background:var(--card-bg);cursor:pointer;text-align:left}.cc-module:hover{border-color:var(--primary);background:var(--subtle-fg)}.cc-code{font-weight:700;color:var(--primary)}
        .cc-alert{padding:12px;border-radius:10px;margin:12px 0;background:var(--yellow-100);color:var(--yellow-900)}
      </style>
      <div class="cc-hero"><div class="cc-code">CC00 · CENTRO DE CONTROL</div><h2>Gestión de obra residencial</h2><div class="cc-muted">Remesas, gastos, contratos, fases, materiales, cierres y auditoría en un solo sistema.</div><div id="cc-demo"></div></div>
      <div id="cc-metrics" class="cc-metrics"></div>
      <h3>Módulos operativos</h3><div id="cc-modules" class="cc-modules"></div>
    `);
    const modules = [
      ["FI01","Fondos e ingresos","Remesas, aportes, depósitos y saldo por fuente","CC Funding Source"],
      ["FI02","Gastos y facturas","Compras, servicios, pagos y comprobación","CC Expense Control"],
      ["CO01","Contratos","Contratistas, valores, pagos y saldos","CC Labor Contract"],
      ["PR01","Fases de obra","Presupuesto, avance, checklist y planificación","CC Construction Phase"],
      ["MM01","Materiales","Existencias, costos y alertas de stock","CC Material Ledger"],
      ["MIGO","Movimientos de inventario","Consumos y ajustes sin stock negativo","CC Inventory Movement"],
      ["MM02","Compras","Solicitudes, cotizaciones y recepción","CC Procurement Request"],
      ["QC01","Avance de obra","Hitos, incidencias y progreso; sin importar fotografías","CC Progress Update"],
      ["CL01","Cierre semanal","Resumen financiero y operativo auditable","CC Weekly Closing"],
      ["AU01","Auditoría","Historial, anulaciones y cambios","CC Audit Log"],
      ["US01","Usuarios y permisos","Acceso operativo sin importar contraseñas","CC User Access"],
      ["MIG","Migración segura","Validar, respaldar, importar y conciliar","Page:construcontrol-migration-console"],
    ];
    body.find("#cc-modules").html(modules.map(m => `<button class="cc-module" data-target="${frappe.utils.escape_html(m[3])}"><span class="cc-code">${m[0]}</span><strong>${m[1]}</strong><div class="cc-muted">${m[2]}</div></button>`).join(""));
    body.on("click", ".cc-module", function(){ const target=$(this).data("target"); if(target.startsWith("Page:")) frappe.set_route(target.split(":")[1]); else frappe.set_route("List", target); });
    const money = value => format_currency(value || 0, "HNL");
    frappe.xcall("erpnext.construcontrol.api.get_dashboard_summary").then(s => {
      const metrics = [["Recibido",money(s.received_hnl)],["Gastado",money(s.spent_hnl)],["Disponible",money(s.available_hnl)],["Contratado",money(s.contracted_hnl)],["Fases",s.phase_count],["Avance",`${s.overall_progress}%`]];
      body.find("#cc-metrics").html(metrics.map(x=>`<div class="cc-metric"><span class="cc-muted">${x[0]}</span><strong>${x[1]}</strong></div>`).join(""));
      if(s.demo_present) body.find("#cc-demo").html(`<div class="cc-alert"><b>Datos demo detectados.</b> Se eliminarán mediante el procedimiento oficial después de una migración conciliada.</div>`);
    }).catch(() => body.find("#cc-metrics").html(`<div class="cc-alert">Todavía no hay datos migrados o no tiene permiso para ver el resumen.</div>`));
};

frappe.pages["construcontrol-migration-console"].on_page_load = function (wrapper) {
  const page = frappe.ui.make_app_page({parent:wrapper,title:"Migración segura de ConstruControl",single_column:true});
  const body=$(wrapper).find(".layout-main-section"); let validationRun=null;
  body.html(`
   <style>.cc-mig{max-width:1100px}.cc-step{border:1px solid var(--border-color);border-radius:12px;padding:16px;margin:12px 0;background:var(--card-bg)}.cc-step h3{margin-top:0}.cc-result{white-space:normal}.cc-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:10px}.cc-chip{padding:10px;border:1px solid var(--border-color);border-radius:9px}.cc-ok{color:var(--green-600)}.cc-bad{color:var(--red-600)}.cc-warning{background:var(--yellow-100);padding:10px;border-radius:8px}.cc-actions{display:flex;gap:8px;flex-wrap:wrap;margin-top:12px}</style>
   <div class="cc-mig">
    <div class="cc-step"><h3>1. Seleccionar respaldo</h3><p>Admite la copia lógica de Supabase <b>.tar.gz</b>, SQL o JSON. Las imágenes, fotografías y rutas de Storage se excluyen. Solo se conserva su metadata.</p><button class="btn btn-primary" id="cc-upload">Seleccionar y validar respaldo</button></div>
    <div class="cc-step"><h3>2. Resultado de la validación</h3><div id="cc-validation" class="cc-result text-muted">Aún no se ha validado un archivo.</div></div>
    <div class="cc-step"><h3>3. Migración definitiva</h3><p>Antes de escribir datos, el sistema crea un respaldo comprimido de MariaDB. La importación es idempotente y concilia cada colección. La limpieza demo se inicia únicamente después de una conciliación exitosa.</p><div class="cc-actions"><button class="btn btn-danger" id="cc-migrate" disabled>Migrar y limpiar demo</button><button class="btn btn-default" id="cc-runs">Ver historial</button></div></div>
   </div>`);
  body.find("#cc-runs").on("click",()=>frappe.set_route("List","ConstruControl Migration Run"));
  body.find("#cc-upload").on("click",()=>new frappe.ui.FileUploader({
    method:"erpnext.construcontrol.api.upload_and_validate", allow_web_link:false, allow_toggle_private:false, allow_take_photo:false,
    restrictions:{allowed_file_types:[".tar.gz",".tgz",".sql",".gz",".json"]},
    on_success:function(_file_doc,r){
      const m=r.message||{}; const v=m.validation||{}; validationRun=m.migration_run||null;
      const countEntries=Object.entries(v.counts||{}).filter(([,n])=>n>0);
      const totals=v.totals||{};
      const issues=[...(v.errors||[]),...(v.warnings||[])];
      body.find("#cc-validation").html(`<div class="${v.valid?'cc-ok':'cc-bad'}"><b>${v.valid?'VALIDACIÓN APROBADA':'VALIDACIÓN BLOQUEADA'}</b></div>
       <p>Huella: <code>${frappe.utils.escape_html(m.source_sha256||'')}</code></p>
       <div class="cc-grid">${countEntries.map(([k,n])=>`<div class="cc-chip"><span class="text-muted">${frappe.utils.escape_html(k)}</span><br><b>${n}</b></div>`).join('')}
       <div class="cc-chip"><span class="text-muted">Ingresos</span><br><b>${format_currency(totals.income_hnl||0,'HNL')}</b></div>
       <div class="cc-chip"><span class="text-muted">Gastos</span><br><b>${format_currency(totals.expense_hnl||0,'HNL')}</b></div>
       <div class="cc-chip"><span class="text-muted">Contratos</span><br><b>${format_currency(totals.contract_hnl||0,'HNL')}</b></div></div>
       ${issues.length?`<div class="cc-warning"><b>Observaciones</b><br>${issues.map(frappe.utils.escape_html).join('<br>')}</div>`:''}
       <p><b>Imágenes a importar: 0.</b> Referencias de evidencia detectadas: ${v.evidence_references||0}.</p>`);
      body.find("#cc-migrate").prop("disabled",!v.valid||!validationRun);
    }
  }));
  body.find("#cc-migrate").on("click",function(){
    if(!validationRun)return;
    frappe.prompt([{fieldname:"confirmation",fieldtype:"Data",label:"Escriba MIGRAR",reqd:1}],values=>{
      frappe.dom.freeze("Creando respaldo, migrando y conciliando. No cierre esta pestaña...");
      frappe.xcall("erpnext.construcontrol.api.execute_migration",{validation_run:validationRun,confirmation:values.confirmation}).then(r=>{
        frappe.dom.unfreeze(); const m=r||{}; frappe.msgprint({title:"Migración completada",indicator:"green",message:`Ejecución: <b>${m.migration_run}</b><br>Respaldo previo: <code>${m.backup_reference}</code><br>Imágenes importadas: <b>0</b><br>Limpieza demo: <b>${m.demo_cleanup?.status||'pendiente'}</b>`});
        body.find("#cc-migrate").prop("disabled",true); frappe.set_route("construcontrol-dashboard");
      }).catch(()=>frappe.dom.unfreeze());
    },"Confirmación obligatoria","Ejecutar migración");
  });
};
